    """
    Recursively merges two nested dictionaries. Adds numeric values when keys conflict,
    and prefers the value from the second dictionary in non-numeric cases.
    """
    result = {}

    # Combine all keys from both dictionaries
    for key in set(d1.keys()).union(d2.keys()):
        if key in d1 and key in d2:
            # If values are both numbers, add them
            if isinstance(d1[key], (int, float)) and isinstance(d2[key], (int, float)):
                result[key] = d1[key] + d2[key]
            else:
                # Otherwise, prefer the value from the second dictionary
                result[key] = d2[key]
        elif key in d1:
            # If only key is in first dictionary, take it as is
            result[key] = d1[key]
        else:
            # If only key is in second dictionary, take it as is
            result[key] = d2[key]

    # Recursively merge nested dictionaries
    for key, value in result.items():
        if isinstance(value, dict):
            result[key] = merge_dicts(d1.get(key, {}), d2.get(key, {}))

    return result

