def groupAnagrams(words):
    # Create a dictionary to hold lists of words grouped by their sorted characters
    anagrams = {}

    for word in words:
        # Sort the characters of the word and use it as a key
        sorted_word = ''.join(sorted(word))

        # If the sorted word is already a key, append the original word
        if sorted_word in anagrams:
            anagrams[sorted_word].append(word)
        else:
            # Otherwise, create a new list for this sorted word with the current word
            anagrams[sorted_word] = [word]

    # Return all groups of anagrams as sorted lists
    return [sorted(group) for group in anagrams.values()]

# Docstring summary: Groups words into anagram groups and returns each group sorted alphabetically.

