        if self._front is None:
            raise IndexError("Dequeue from empty queue")  # Queue is empty, cannot dequeue
        value = self._front.value  # Get the value of the front node
        self._front = self._front.next  # Update front to point to the next node
        if self._front is None:
            self._rear = None  # If queue becomes empty, set rear to None as well
        self._size -= 1             # Decrement the size of the queue
        return value                # Return the dequeued value

    def __len__(self) -> int:
